  describe "options_strong_em_underscore" do
    test "Strong and em tags use underscore symbol instead of asterisk" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | strong_em_symbol: "_"}
      {:ok, result} = HtmlToMarkdownRs.convert("<p><strong>bold</strong> and <em>italic</em></p>", options)
      assert String.contains?(to_string(result.content), "__bold__")
      assert String.contains?(to_string(result.content), "_italic_")
    end
  end

  describe "options_sub_symbol_tilde" do
    test "Subscript rendered with tilde symbol" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | sub_symbol: "~"}
      {:ok, result} = HtmlToMarkdownRs.convert("<p>H<sub>2</sub>O</p>", options)
      assert String.contains?(to_string(result.content), "~2~")
    end
  end

  describe "options_sup_symbol_caret" do
    test "Superscript rendered with caret symbol" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | sup_symbol: "^"}
      {:ok, result} = HtmlToMarkdownRs.convert("<p>x<sup>2</sup></p>", options)
      assert String.contains?(to_string(result.content), "^2^")
    end
  end

  describe "options_whitespace_normalized" do
    test "Normalized whitespace mode collapses multiple spaces" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | whitespace_mode: :normalized}
      {:ok, result} = HtmlToMarkdownRs.convert("<p>Text   with    extra   spaces.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "Text")
      assert String.contains?(to_string(result.content), "with")
      assert String.contains?(to_string(result.content), "extra")
      assert String.contains?(to_string(result.content), "spaces.")
    end
  end

  describe "options_whitespace_strict" do
    test "Strict whitespace mode preserves whitespace as-is" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | whitespace_mode: :strict}
      {:ok, result} = HtmlToMarkdownRs.convert("<p>Preserved   spacing.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "Preserved")
      assert String.contains?(to_string(result.content), "spacing.")
    end
  end

  describe "options_wrap_disabled" do
    test "Wrap option disabled preserves long lines without breaking" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | wrap: false}
      {:ok, result} = HtmlToMarkdownRs.convert("<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", options)
      assert String.contains?(to_string(result.content), "This is a long paragraph that should not be wrapped at all because wrapping is disabled.")
    end
  end

  describe "options_wrap_enabled" do
    test "Wrap option enabled with custom width wraps long lines" do
      options = HtmlToMarkdownRs.conversionoptions_default()
      options = %{options | wrap: true}
      options = %{options | wrap_width: 40}
      {:ok, result} = HtmlToMarkdownRs.convert("<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "This is a long paragraph")
    end
  end
end
